code = """import json

# Load the EMA results
with open('file_storage/functions.execute_python:54.json', 'r') as f:
    data = json.load(f)

# Format the results as a table
results = data['ema_results']

output = []
output.append('CPC Technology Areas in Germany with Highest EMA (H2 2019)')
output.append('=' * 60)
output.append('')
output.append('Rank  CPC Group      Highest EMA  Best Month  Total Patents')
output.append('-' * 60)

for i, r in enumerate(results[:10]):
    line = f"{i+1:4d}  {r['cpc_group_code']:12s}  {r['max_ema']:8.2f}  {r['best_month_name']:10s}  {r['total_patents']:8d}"
    output.append(line)

for line in output:
    print(line)

# Save formatted results
with open('german_cpc_ema_results.json', 'w') as f:
    json.dump(results[:10], f, indent=2)

print()
print('Results saved to file: german_cpc_ema_results.json')

result_dict = {
    'top_cpc_groups': results[:10],
    'analysis_period': 'July-December 2019 (H2)',
    'smoothing_factor': 0.1
}

print('__RESULT__:')
print(json.dumps(result_dict))"""

